    27|
    28|/* ── Shipping zones ─────────────────────────────────────────── */
    29|const SHIPPING_ZONES = [
    30|  { id: 'asuncion', label: 'Asunción', cost: 15_000 },
    31|  { id: 'gran-asuncion', label: 'Gran Asunción', cost: 25_000 },
    32|  { id: 'interior', label: 'Interior', cost: 40_000 },
    33|] as const;
    34|
    35|type ShippingZoneId = (typeof SHIPPING_ZONES)[number]['id'];
    36|
    37|const FREE_SHIPPING_THRESHOLD = 300_000;
    38|
    39|/* ── City → zone mapping ────────────────────────────────────── */
    40|const CITY_ZONE_MAP: Record<string, ShippingZoneId> = {
    41|  asuncion: 'asuncion',
    42|  asunción: 'asuncion',
    43|  'fernando de la mora': 'gran-asuncion',
    44|  lambare: 'gran-asuncion',
    45|  lambaré: 'gran-asuncion',
    46|  'san lorenzo': 'gran-asuncion',
    47|  luque: 'gran-asuncion',
    48|  capiata: 'gran-asuncion',
    49|  capiatá: 'gran-asuncion',
    50|  limpio: 'gran-asuncion',
    51|  'mariano roque alonso': 'gran-asuncion',
    52|  nemby: 'gran-asuncion',
    53|  ñemby: 'gran-asuncion',
    54|  'villa elisa': 'gran-asuncion',
    55|  'san antonio': 'gran-asuncion',
    56|  ita: 'gran-asuncion',
    57|  itá: 'gran-asuncion',
    58|  ypacarai: 'gran-asuncion',
    59|  ypacaraí: 'gran-asuncion',
    60|  aregua: 'gran-asuncion',
    61|  areguá: 'gran-asuncion',
    62|};
    63|
    64|type PaymentMethod = 'transfer' | 'cod' | null;
    65|
    66|/* ── Bank account details ────────────────────────────────────── */
    67|const BANK_DETAILS = {
    68|  bank: 'Banco Itaú',
    69|  accountName: 'Fun4Me Store SRL',
    70|  accountNumber: '[REDACTED_PHONE]',
    71|  ruc: '[REDACTED_PHONE]',
    72|  ci: '4.567.890',
    73|};
    74|
    75|export default function CheckoutPage() {
    76|  const router = useRouter();
    77|  const items = useCartStore((s) => s.items);
    78|  const totalPrice = useCartStore((s) => s.totalPrice);
    79|  const clearCart = useCartStore((s) => s.clearCart);
    80|
    81|  const subtotal = totalPrice();
    82|
    83|  /* ── Form state ──────────────────────────────────────────── */
    84|  const [name, setName] = useState('');
    85|  const [phone, setPhone] = useState('');
    86|  const [address, setAddress] = useState('');
    87|  const [city, setCity] = useState('');
    88|  const [neighborhood, setNeighborhood] = useState('');
    89|  const [notes, setNotes] = useState('');
    90|  const [shippingZone, setShippingZone] = useState<ShippingZoneId | null>(null);
    91|  const [paymentMethod, setPaymentMethod] = useState<PaymentMethod>(null);
    92|  const [receiptFile, setReceiptFile] = useState<File | null>(null);
    93|  const [isSubmitting, setIsSubmitting] = useState(false);
    94|  const [errors, setErrors] = useState<Record<string, string>>({});
    95|  const [mounted, setMounted] = useState(false);
    96|
    97|  useEffect(() => {
    98|    setMounted(true);
    99|  }, []);
   100|
   101|  /* ── Auto-detect shipping zone from city ─────────────────── */
   102|  useEffect(() => {
   103|    const normalized = city.trim().toLowerCase();
   104|    if (CITY_ZONE_MAP[normalized]) {
   105|      setShippingZone(CITY_ZONE_MAP[normalized]);
   106|    } else if (normalized.length > 2 && !CITY_ZONE_MAP[normalized]) {
   107|      setShippingZone('interior');
   108|    }
   109|  }, [city]);
   110|
   111|  /* ── Computed values ─────────────────────────────────────── */
   112|  const selectedZone = useMemo(
   113|    () => SHIPPING_ZONES.find((z) => z.id === shippingZone) ?? null,
   114|    [shippingZone],
   115|  );
   116|
   117|  const isFreeShipping = subtotal >= FREE_SHIPPING_THRESHOLD;
   118|  const shippingCost = isFreeShipping ? 0 : (selectedZone?.cost ?? 0);
   119|  const total = subtotal + shippingCost;
   120|
   121|  /* ── Validation ──────────────────────────────────────────── */
   122|  function validate(): boolean {
   123|    const newErrors: Record<string, string> = {};
   124|    if (!name.trim()) newErrors.name = 'Ingresá tu nombre completo';
   125|    if (!phone.trim()) newErrors.phone = 'Ingresá tu número de teléfono';
   126|    else if (!/^0\d{8,10}$/.test(phone.replace(/\s/g, '')))
   127|      newErrors.phone = 'Formato: [REDACTED_PHONE]';
   128|    if (!address.trim()) newErrors.address = 'Ingresá tu dirección';
   129|    if (!city.trim()) newErrors.city = 'Ingresá tu ciudad';
   130|    if (!neighborhood.trim()) newErrors.neighborhood = 'Ingresá tu barrio';
   131|    if (!shippingZone) newErrors.shippingZone = 'Seleccioná tu zona de envío';
   132|    if (!paymentMethod) newErrors.paymentMethod = 'Elegí un método de pago';
   133|    setErrors(newErrors);
   134|    return Object.keys(newErrors).length === 0;
   135|  }
   136|
   137|  /* ── Submit order ────────────────────────────────────────── */
   138|  async function handleSubmit() {
   139|    if (!validate()) return;
   140|    setIsSubmitting(true);
   141|
   142|    try {
   143|      // Generate order number (timestamp-based for now)
   144|      const orderNumber = `F4M-${Date.now().toString(36).toUpperCase()}`;
   145|
   146|      // Store order info in sessionStorage for the confirmation page
   147|      const orderData = {
   148|        orderNumber,
   149|        customerName: name,
   150|        customerPhone: phone,
   151|        customerAddress: `${address}, ${neighborhood}, ${city}`,
   152|        shippingZone: selectedZone?.label,
   153|        shippingCost,
   154|        paymentMethod,
   155|        items: items.map((item) => ({
   156|          name: item.name,
   157|          quantity: item.quantity,
   158|          price: item.price,
   159|          total: item.price * item.quantity,
   160|        })),
   161|        subtotal,
   162|        total,
   163|        createdAt: new Date().toISOString(),
   164|      };
   165|
   166|      sessionStorage.setItem('fun4me-last-order', JSON.stringify(orderData));
   167|
   168|      // Clear cart and redirect
   169|      clearCart();
   170|      router.push('/confirmacion');
   171|    } catch {
   172|      setErrors({ submit: 'Ocurrió un error. Por favor intentá de nuevo.' });
   173|    } finally {
   174|      setIsSubmitting(false);
   175|    }
   176|  }
   177|
   178|  /* ── Render ──────────────────────────────────────────────── */
   179|
   180|  // Empty cart guard
   181|  if (mounted && items.length === 0) {
   182|    return (
   183|      <div className="container mx-auto px-4 py-20 text-center">
   184|        <ShoppingCart className="mx-auto mb-6 h-24 w-24 text-muted-foreground/20" />
   185|        <h1 className="text-2xl font-bold">Tu carrito está vacío</h1>
   186|        <p className="mt-2 text-muted-foreground">
   187|          Agregá productos antes de ir al checkout.
   188|        </p>
   189|        <Link href="/">
   190|          <Button className="mt-6 bg-gradient-to-r from-rose-500 to-purple-600 text-white">
   191|            Ir a la Tienda
   192|          </Button>
   193|        </Link>
   194|      </div>
   195|    );
   196|  }
   197|
   198|  return (
   199|    <div className="container mx-auto px-4 py-8">
   200|      {/* Breadcrumbs */}
   201|      <nav className="mb-6 flex items-center gap-2 text-sm text-muted-foreground">
   202|        <Link href="/" className="hover:text-foreground">
   203|          Inicio
   204|        </Link>
   205|        <span>/</span>
   206|        <Link href="/carrito" className="hover:text-foreground">
   207|          Carrito
   208|        </Link>
   209|        <span>/</span>
   210|        <span className="text-foreground">Checkout</span>
   211|      </nav>
   212|
   213|      <div className="mb-8 flex items-center gap-3">
   214|        <Link href="/carrito">
   215|          <Button variant="ghost" size="icon">
   216|            <ArrowLeft className="h-5 w-5" />
   217|          </Button>
   218|        </Link>
   219|        <h1 className="text-3xl font-bold">Finalizar Compra</h1>
   220|      </div>
